package github.chains;

import com.github.javaparser.JavaParser;
import com.github.javaparser.ParseResult;
import com.github.javaparser.ast.CompilationUnit;
import com.github.javaparser.ast.body.ConstructorDeclaration;
import com.github.javaparser.ast.body.MethodDeclaration;
import com.github.javaparser.ast.expr.ObjectCreationExpr;
import com.github.javaparser.ast.expr.SuperExpr;
import com.github.javaparser.ast.nodeTypes.NodeWithStatements;
import com.github.javaparser.ast.stmt.ExpressionStmt;

import java.io.File;
import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.stream.Collectors;

public class Main {

    private static final JavaParser javaParser = new JavaParser();

    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);

        List<Path> javaFiles = Files.walk(sourceDir)
            .filter(p -> p.toString().endsWith(".java"))
            .collect(Collectors.toList());

        for (Path file : javaFiles) {
            transformFile(file);
        }

        System.out.println("Transformation complete!");
    }

    private static void transformFile(Path file) throws IOException {
        String content = Files.readString(file);
        ParseResult<CompilationUnit> result = javaParser.parse(content);

        if (!result.isSuccessful() || result.getResult().isEmpty()) {
            System.err.println("Failed to parse: " + file);
            return;
        }

        CompilationUnit cu = result.getResult().get();
        boolean modified = false;

        // Fix 1: ModelConstructor - Change super(Model.class) to super()
        // The Constructor class in SnakeYAML 2.0 no longer accepts Class parameter
        List<ConstructorDeclaration> constructors = cu.findAll(ConstructorDeclaration.class);
        for (ConstructorDeclaration constructor : constructors) {
            List<ExpressionStmt> statements = constructor.getBody().getStatements()
                .stream()
                .filter(s -> s instanceof ExpressionStmt)
                .map(s -> (ExpressionStmt) s)
                .collect(Collectors.toList());

            for (ExpressionStmt stmt : statements) {
                if (stmt.getExpression() instanceof SuperExpr) {
                    SuperExpr superExpr = (SuperExpr) stmt.getExpression();
                    if (superExpr.getArguments().isPresent() && 
                        superExpr.getArguments().get().size() > 0) {
                        // Remove arguments from super() call
                        superExpr.getArguments().get().clear();
                        modified = true;
                    }
                }
            }
        }

        // Fix 2: YamlModelReader - Change new Representer() to new ModelRepresenter()
        // The Representer no-arg constructor is removed in SnakeYAML 2.0
        List<ObjectCreationExpr> objectCreations = cu.findAll(ObjectCreationExpr.class);
        for (ObjectCreationExpr creation : objectCreations) {
            if (creation.getType().asString().equals("Representer")) {
                // Replace with ModelRepresenter which extends Representer with proper constructor
                creation.setType("ModelRepresenter");
                modified = true;
            }
        }

        // Fix 3: ModelRepresenter - Remove throws IntrospectionException from getProperties
        List<MethodDeclaration> methods = cu.findAll(MethodDeclaration.class);
        for (MethodDeclaration method : methods) {
            if (method.getNameAsString().equals("getProperties")) {
                method.getThrownExceptions().removeIf(t -> t.asString().equals("IntrospectionException"));
                modified = true;
            }
        }

        if (modified) {
            String transformed = cu.toString();
            Files.writeString(file, transformed);
            System.out.println("Transformed: " + file);
        }
    }
}

